(function() {
  const target = document.querySelector('.ytp-next-button, a.ytp-next-button, [data-action="next"], .vp-next');
  if (target instanceof HTMLElement) { target.click(); return; }
  const playlist = document.querySelector('ytd-playlist-panel-renderer a#wc-endpoint:not([aria-selected="true"]) + a#wc-endpoint');
  if (playlist instanceof HTMLElement) playlist.click();
})();

(function() {
  const target = document.querySelector('.ytp-prev-button, [data-action="previous"], .vp-previous');
  if (target instanceof HTMLElement) target.click();
})();
